+/**
+ * Notification history service — logs and queries sent notification history.
+ *
+ * Listens to notification:sent and notification:failed events on the EventBus
+ * and persists a log entry for each. Provides query methods for retrieving
+ * notification history filtered by recipient, type, channel, status, or date range.
+ *
+ * Depends on:
+ * - EventBus for receiving notification outcome events
+ * - NotificationLogRepository for persistence
+ */
+
+import type { EventBus } from '../events/event-bus.js';
+import type { NotificationSentEvent, NotificationFailedEvent } from '../events/event-types.js';
+import type { NotificationLog, NotificationHistoryQuery } from '../models/notification-log.js';
+import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
+import { Logger } from '../utils/logger.js';
+
+let nextId = 1;
+
+function generateLogId(): string {
+  return `nlog-${String(nextId++).padStart(4, '0')}`;
+}
+
+export function resetNotificationLogIdCounter(): void {
+  nextId = 1;
+}
+
+export class NotificationHistoryService {
+  private logger = new Logger('NotificationHistoryService');
+
+  constructor(
+    private eventBus: EventBus,
+    private repository: NotificationLogRepository,
+  ) {
+    this.registerEventHandlers();
+  }
+
+  private registerEventHandlers(): void {
+    this.eventBus.on<NotificationSentEvent>('notification:sent', (event) => {
+      this.logNotification(event.notification, 'sent');
+    });
+
+    this.eventBus.on<NotificationFailedEvent>('notification:failed', (event) => {
+      this.logNotification(event.notification, 'failed', event.error);
+    });
+  }
+
+  private logNotification(
+    notification: { id: string; type: string; channel: string; recipient: string; subject: string; metadata: Record<string, unknown>; createdAt: Date; sentAt?: Date; error?: string },
+    status: 'sent' | 'failed',
+    error?: string,
+  ): void {
+    const log: NotificationLog = {
+      id: generateLogId(),
+      notificationId: notification.id,
+      recipient: notification.recipient,
+      channel: notification.channel as NotificationLog['channel'],
+      type: notification.type as NotificationLog['type'],
+      subject: notification.subject,
+      status,
+      error: error ?? notification.error,
+      metadata: notification.metadata,
+      createdAt: notification.createdAt,
+      deliveredAt: notification.sentAt,
+    };
+
+    this.repository.save(log);
+    this.logger.info(
+      `Logged ${status} notification ${notification.id} to ${notification.recipient}`,
+    );
+  }
+
+  /**
+   * Query notification history with optional filters.
+   */
+  query(filters: NotificationHistoryQuery): NotificationLog[] {
+    return this.repository.findAll((log) => {
+      if (filters.recipient && log.recipient !== filters.recipient) return false;
+      if (filters.type && log.type !== filters.type) return false;
+      if (filters.channel && log.channel !== filters.channel) return false;
+      if (filters.status && log.status !== filters.status) return false;
+      if (filters.startDate && log.createdAt < filters.startDate) return false;
+      if (filters.endDate && log.createdAt > filters.endDate) return false;
+      return true;
+    });
+  }
+
+  /**
+   * Get all log entries.
+   */
+  getAll(): NotificationLog[] {
+    return this.repository.findAll();
+  }
+
+  /**
+   * Get log entries for a specific recipient.
+   */
+  getByRecipient(recipient: string): NotificationLog[] {
+    return this.repository.findByRecipient(recipient);
+  }
+
+  /**
+   * Get log entries by notification type.
+   */
+  getByType(type: NotificationLog['type']): NotificationLog[] {
+    return this.repository.findByType(type);
+  }
+
+  /**
+   * Get log entries by delivery channel.
+   */
+  getByChannel(channel: NotificationLog['channel']): NotificationLog[] {
+    return this.repository.findByChannel(channel);
+  }
+
+  /**
+   * Get log entries within a date range.
+   */
+  getByDateRange(startDate: Date, endDate: Date): NotificationLog[] {
+    return this.repository.findByDateRange(startDate, endDate);
+  }
+
+  /**
+   * Get the total count of log entries.
+   */
+  getCount(): number {
+    return this.repository.count();
+  }
+}

