import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import { Database } from '../../src/utils/database.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import {
  NotificationHistoryService,
  resetNotificationLogIdCounter,
} from '../../src/services/notification-history.service.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { Notification } from '../../src/models/notification.js';
import type { NotificationSentEvent, NotificationFailedEvent } from '../../src/events/event-types.js';

describe('NotificationHistoryService', () => {
  let eventBus: EventBus;
  let db: Database;
  let repository: NotificationLogRepository;
  let historyService: NotificationHistoryService;

  beforeEach(() => {
    eventBus = new EventBus();
    db = new Database();
    repository = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(eventBus, repository);
    resetNotificationLogIdCounter();
  });

  function makeSentEvent(overrides: Partial<Notification> = {}): NotificationSentEvent {
    return {
      type: 'notification:sent',
      notification: {
        id: 'notif-0001',
        type: 'order_confirmation',
        channel: 'email',
        recipient: 'alice@example.com',
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
        metadata: { orderId: 'order-1', userId: 'user-1' },
        status: 'sent',
        createdAt: new Date('2026-01-15T10:00:00Z'),
        sentAt: new Date('2026-01-15T10:00:01Z'),
        ...overrides,
      },
      timestamp: new Date(),
    };
  }

  function makeFailedEvent(overrides: Partial<Notification> = {}): NotificationFailedEvent {
    return {
      type: 'notification:failed',
      notification: {
        id: 'notif-0002',
        type: 'user_welcome',
        channel: 'email',
        recipient: 'bob@example.com',
        subject: 'Welcome!',
        body: 'Welcome to TaskFlow Pro.',
        metadata: { userId: 'user-2' },
        status: 'failed',
        createdAt: new Date('2026-01-15T11:00:00Z'),
        error: 'SMTP connection refused',
        ...overrides,
      },
      error: 'SMTP connection refused',
      timestamp: new Date(),
    };
  }

  describe('logging sent notifications', () => {
    it('should log a sent notification', async () => {
      await eventBus.emit(makeSentEvent());

      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0]?.status).toBe('sent');
      expect(logs[0]?.recipient).toBe('alice@example.com');
      expect(logs[0]?.channel).toBe('email');
      expect(logs[0]?.type).toBe('order_confirmation');
      expect(logs[0]?.notificationId).toBe('notif-0001');
      expect(logs[0]?.deliveredAt).toEqual(new Date('2026-01-15T10:00:01Z'));
    });

    it('should log a failed notification', async () => {
      await eventBus.emit(makeFailedEvent());

      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0]?.status).toBe('failed');
      expect(logs[0]?.error).toBe('SMTP connection refused');
      expect(logs[0]?.recipient).toBe('bob@example.com');
    });

    it('should generate sequential log IDs', async () => {
      await eventBus.emit(makeSentEvent());
      await eventBus.emit(makeSentEvent({ id: 'notif-0002', recipient: 'bob@example.com' }));

      const logs = historyService.getAll();
      expect(logs[0]?.id).toBe('nlog-0001');
      expect(logs[1]?.id).toBe('nlog-0002');
    });
  });

  describe('querying by recipient', () => {
    it('should return logs for a specific recipient', async () => {
      await eventBus.emit(makeSentEvent({ recipient: 'alice@example.com' }));
      await eventBus.emit(makeSentEvent({ id: 'notif-0002', recipient: 'bob@example.com' }));
      await eventBus.emit(makeSentEvent({ id: 'notif-0003', recipient: 'alice@example.com' }));

      const aliceLogs = historyService.getByRecipient('alice@example.com');
      expect(aliceLogs).toHaveLength(2);

      const bobLogs = historyService.getByRecipient('bob@example.com');
      expect(bobLogs).toHaveLength(1);

      const charlieLogs = historyService.getByRecipient('charlie@example.com');
      expect(charlieLogs).toHaveLength(0);
    });
  });

  describe('querying by type', () => {
    it('should return logs for a specific notification type', async () => {
      await eventBus.emit(makeSentEvent({ type: 'order_confirmation' }));
      await eventBus.emit(makeSentEvent({ id: 'notif-0002', type: 'user_welcome' }));
      await eventBus.emit(makeSentEvent({ id: 'notif-0003', type: 'order_confirmation' }));

      const orderLogs = historyService.getByType('order_confirmation');
      expect(orderLogs).toHaveLength(2);

      const welcomeLogs = historyService.getByType('user_welcome');
      expect(welcomeLogs).toHaveLength(1);
    });
  });

  describe('querying by channel', () => {
    it('should return logs for a specific channel', async () => {
      await eventBus.emit(makeSentEvent({ channel: 'email' }));
      await eventBus.emit(makeSentEvent({ id: 'notif-0002', channel: 'webhook' }));

      const emailLogs = historyService.getByChannel('email');
      expect(emailLogs).toHaveLength(1);

      const webhookLogs = historyService.getByChannel('webhook');
      expect(webhookLogs).toHaveLength(1);
    });
  });

  describe('querying by date range', () => {
    it('should return logs within a date range', async () => {
      await eventBus.emit(makeSentEvent({
        createdAt: new Date('2026-01-10T10:00:00Z'),
      }));
      await eventBus.emit(makeSentEvent({
        id: 'notif-0002',
        createdAt: new Date('2026-01-15T10:00:00Z'),
      }));
      await eventBus.emit(makeSentEvent({
        id: 'notif-0003',
        createdAt: new Date('2026-01-20T10:00:00Z'),
      }));

      const logs = historyService.getByDateRange(
        new Date('2026-01-12T00:00:00Z'),
        new Date('2026-01-18T00:00:00Z'),
      );
      expect(logs).toHaveLength(1);
      expect(logs[0]?.notificationId).toBe('notif-0002');
    });
  });

  describe('combined query filters', () => {
    it('should filter by multiple criteria', async () => {
      await eventBus.emit(makeSentEvent({
        recipient: 'alice@example.com',
        type: 'order_confirmation',
      }));
      await eventBus.emit(makeSentEvent({
        id: 'notif-0002',
        recipient: 'alice@example.com',
        type: 'user_welcome',
      }));
      await eventBus.emit(makeSentEvent({
        id: 'notif-0003',
        recipient: 'bob@example.com',
        type: 'order_confirmation',
      }));

      const results = historyService.query({
        recipient: 'alice@example.com',
        type: 'order_confirmation',
      });
      expect(results).toHaveLength(1);
      expect(results[0]?.notificationId).toBe('notif-0001');
    });

    it('should filter by status', async () => {
      await eventBus.emit(makeSentEvent());
      await eventBus.emit(makeFailedEvent());

      const sent = historyService.query({ status: 'sent' });
      expect(sent).toHaveLength(1);

      const failed = historyService.query({ status: 'failed' });
      expect(failed).toHaveLength(1);
    });

    it('should return all logs when no filters provided', async () => {
      await eventBus.emit(makeSentEvent());
      await eventBus.emit(makeFailedEvent());

      const all = historyService.query({});
      expect(all).toHaveLength(2);
    });
  });

  describe('count', () => {
    it('should return the total number of log entries', async () => {
      expect(historyService.getCount()).toBe(0);

      await eventBus.emit(makeSentEvent());
      expect(historyService.getCount()).toBe(1);

      await eventBus.emit(makeFailedEvent());
      expect(historyService.getCount()).toBe(2);
    });
  });

  describe('end-to-end integration with NotificationService', () => {
    it('should log notifications dispatched through NotificationService', async () => {
      resetNotificationIdCounter();
      const notificationService = new NotificationService(eventBus);
      const emailAdapter = new EmailAdapter();
      notificationService.registerAdapter(emailAdapter);

      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          ],
          total: 20,
          status: 'pending' as const,
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member' as const,
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      });

      // The notification service sends via the adapter, which emits notification:sent,
      // which the history service picks up
      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0]?.status).toBe('sent');
      expect(logs[0]?.recipient).toBe('alice@example.com');
      expect(logs[0]?.type).toBe('order_confirmation');
      expect(logs[0]?.channel).toBe('email');
      expect(logs[0]?.subject).toContain('Order Confirmation');
    });
  });
});
